class Solution:
    def minHeightShelves(self, books, shelfWidth):
        n = len(books)
        INF = float('inf')
        best = [INF] * (n + 1)
        best[0] = 0
        for i in range(1, n + 1):
            width = 0
            height = 0
            j = i
            while j >= 1:
                width += books[j - 1][0]
                if width > shelfWidth:
                    break
                height = max(height, books[j - 1][1])
                if best[j - 1] + height < best[i]:
                    best[i] = best[j - 1] + height
                j -= 1
        return best[n]

