class Solution:
    def minHeightShelves(self, books, shelfWidth):
        n = len(books)
        dp = [0] + [float('inf')] * n
        for i in range(1, n + 1):
            w = 0
            h = 0
            for j in range(i, 0, -1):
                w += books[j - 1][0]
                if w > shelfWidth:
                    break
                h = max(h, books[j - 1][1])
                dp[i] = min(dp[i], dp[j - 1] + h)
        return dp[n]

