var minHeightShelves = function(books, shelfWidth) {
    const n = books.length;
    const dp = new Array(n + 1).fill(Infinity);
    dp[0] = 0;
    for (let i = 1; i <= n; i++) {
        let w = 0, h = 0;
        for (let j = i; j >= 1; j--) {
            w += books[j - 1][0];
            if (w > shelfWidth) break;
            h = Math.max(h, books[j - 1][1]);
            dp[i] = Math.min(dp[i], dp[j - 1] + h);
        }
    }
    return dp[n];
};
